public class StringBenchmark {
    public static void main(String[] args) {
        int n = 50_000;
        char[] chars = new char[n];
        for (int i=0;i<n;i++) chars[i]=(char)('a'+i%26);

        // Approach 1: String concatenation O(n²)
        long s1 = System.currentTimeMillis();
        String result1 = "";
        for (char c : chars) result1 += c;
        long t1 = System.currentTimeMillis() - s1;

        // Approach 2: StringBuilder O(n)
        long s2 = System.currentTimeMillis();
        StringBuilder sb = new StringBuilder();
        for (char c : chars) sb.append(c);
        String result2 = sb.toString();
        long t2 = Math.max(System.currentTimeMillis() - s2, 1);

        System.out.println("n = " + n);
        System.out.println("String +=:      " + t1 + "ms  (O(n²))");
        System.out.println("StringBuilder:  " + t2 + "ms  (O(n))");
        System.out.println("Ratio: " + (t1/t2) + "x slower with +=" );
        System.out.println("Same result: " + result1.equals(result2));
        System.out.println();
        System.out.println("Rule: NEVER use += in a loop. Always StringBuilder.");
    }
}

