public class ReverseString {
    // O(n) time, O(n) space
    static String reverseBuiltin(String s) {
        return new StringBuilder(s).reverse().toString();
    }
    // O(n) time, O(n) space (char[] needed — String immutable)
    static String reverseTwoPointer(String s) {
        char[] chars = s.toCharArray();
        int lo = 0, hi = chars.length - 1;
        while (lo < hi) { char tmp=chars[lo]; chars[lo]=chars[hi]; chars[hi]=tmp; lo++; hi--; }
        return new String(chars);
    }
    // O(n) time, O(n) stack space — avoid for large strings
    static String reverseRecursive(String s) {
        if (s.length() <= 1) return s;
        return reverseRecursive(s.substring(1)) + s.charAt(0);
        // WARNING: substring(1) creates new String each call → O(n²) total!
        // Better recursive: work on char[] indices
    }
    public static void main(String[] args) {
        String[] tests = {"Zerodha", "racecar", "a", ""};
        for (String t : tests) {
            String b=reverseBuiltin(t), tp=reverseTwoPointer(t);
            System.out.println("'" + t + "' → '" + b + "' all agree: " + b.equals(tp));
        }
        System.out.println();
        System.out.println("Best: StringBuilder.reverse() — clean, O(n)");
        System.out.println("Avoid: recursive with substring() — actually O(n²)!");
        System.out.println("In-place: use char[] (String is immutable)");
    }
}

