public class ValidAnagram {
    public static boolean isAnagram(String s, String t) {
        if (s.length() != t.length()) return false;
        int[] freq = new int[26]; // lowercase letters only
        for (int i = 0; i < s.length(); i++) {
            freq[s.charAt(i) - 'a']++; // count s chars
            freq[t.charAt(i) - 'a']--; // uncount t chars
        }
        for (int f : freq) if (f != 0) return false;
        return true;
    }
    public static void main(String[] args) {
        System.out.println(isAnagram("anagram", "nagaram")); // true
        System.out.println(isAnagram("rat", "car"));         // false
        System.out.println(isAnagram("a", "a"));             // true
        System.out.println("O(n) time, O(1) space — int[26] frequency array");
        System.out.println("Why O(1) space: array size 26 is constant regardless of n");
    }
}

