import java.util.*;
public class RomanToInt {
    public static int romanToInt(String s) {
        Map<Character,Integer> val = new HashMap<>();
        val.put('I',1); val.put('V',5); val.put('X',10); val.put('L',50);
        val.put('C',100); val.put('D',500); val.put('M',1000);
        int result = 0;
        for (int i = 0; i < s.length(); i++) {
            int curr = val.get(s.charAt(i));
            int next = i+1 < s.length() ? val.get(s.charAt(i+1)) : 0;
            if (curr < next) result -= curr; // subtraction case (IV, IX, etc.)
            else result += curr;
        }
        return result;
    }
    public static void main(String[] args) {
        System.out.println(romanToInt("III"));     // 3
        System.out.println(romanToInt("IV"));      // 4
        System.out.println(romanToInt("MCMXCIV")); // 1994
        System.out.println("O(n) time, O(1) space (7 fixed map entries)");
    }
}

