public class CountAndSay {
    public static String countAndSay(int n) {
        String curr = "1";
        for (int i = 2; i <= n; i++) {
            StringBuilder next = new StringBuilder();
            int j = 0;
            while (j < curr.length()) {
                char c = curr.charAt(j);
                int count = 0;
                while (j < curr.length() && curr.charAt(j) == c) { j++; count++; }
                next.append(count).append(c); // 'count' occurrences of 'c'
            }
            curr = next.toString();
        }
        return curr;
    }
    public static void main(String[] args) {
        for (int i=1;i<=6;i++) System.out.println(i + ": " + countAndSay(i));
        // Expected: 1:1, 2:11, 3:21, 4:1211, 5:111221, 6:312211
    }
}

