import java.util.*;
public class DecodeString {
    public static String decodeString(String s) {
        Deque<Integer> counts = new ArrayDeque<>();
        Deque<StringBuilder> strings = new ArrayDeque<>();
        StringBuilder curr = new StringBuilder();
        int k = 0;
        for (char c : s.toCharArray()) {
            if (Character.isDigit(c)) {
                k = k * 10 + (c - '0'); // multi-digit numbers
            } else if (c == '[') {
                counts.push(k);
                strings.push(curr);
                curr = new StringBuilder();
                k = 0;
            } else if (c == ']') {
                int repeat = counts.pop();
                StringBuilder prev = strings.pop();
                for (int i = 0; i < repeat; i++) prev.append(curr);
                curr = prev;
            } else {
                curr.append(c);
            }
        }
        return curr.toString();
    }
    public static void main(String[] args) {
        System.out.println(decodeString("3[a]2[bc]"));     // aaabcbc
        System.out.println(decodeString("3[a2[c]]"));      // accaccacc
        System.out.println(decodeString("2[abc]3[cd]ef")); // abcabccdcdcdef
        System.out.println("O(n×max_k) time — each char processed once per nesting");
    }
}

