import java.util.Arrays;
public class StringCompression {
    public static int compress(char[] chars) {
        int write = 0, read = 0;
        while (read < chars.length) {
            char c = chars[read];
            int count = 0;
            while (read < chars.length && chars[read] == c) { read++; count++; }
            chars[write++] = c;
            if (count > 1) {
                for (char digit : String.valueOf(count).toCharArray())
                    chars[write++] = digit;
            }
        }
        return write;
    }
    public static void main(String[] args) {
        char[] a = {'a','a','b','c','c','c','c','c','a','a','a'};
        int len = compress(a);
        System.out.println(len + ": " + new String(Arrays.copyOf(a, len))); // 6: a2bc5a3
        char[] b = {'a'};
        System.out.println(compress(b)); // 1
        char[] c = {'a','b','b','b','b','b','b','b','b','b','b','b','b'};
        len = compress(c);
        System.out.println(len + ": " + new String(Arrays.copyOf(c, len))); // 4: ab12
        System.out.println("O(n) time, O(1) extra space — read/write two pointers");
    }
}

