import java.util.*;
public class SimplifyPath {
    public static String simplifyPath(String path) {
        Deque<String> stack = new ArrayDeque<>();
        for (String part : path.split("/")) {
            if (part.equals("..")) {
                if (!stack.isEmpty()) stack.pop(); // go up one level
            } else if (!part.equals(".") && !part.isEmpty()) {
                stack.push(part); // valid directory name
            }
            // '.' and empty strings: skip
        }
        StringBuilder result = new StringBuilder();
        // Build path from bottom of stack (stack is LIFO, we want root-first)
        List<String> parts = new ArrayList<>(stack);
        Collections.reverse(parts);
        for (String p : parts) result.append("/").append(p);
        return result.length() == 0 ? "/" : result.toString();
    }
    public static void main(String[] args) {
        System.out.println(simplifyPath("/home/"));           // /home
        System.out.println(simplifyPath("/a/./b/../../c/"));  // /c
        System.out.println(simplifyPath("/../"));             // /
        System.out.println(simplifyPath("/home//foo/"));      // /home/foo
        System.out.println("O(n) time O(n) space");
    }
}

