import java.util.*;
public class StringSynthesis {
    static String reverseWords(String s) {
        String[] words = s.trim().split("\\s+"); // split on any whitespace
        StringBuilder sb = new StringBuilder();
        for (int i=words.length-1; i>=0; i--) {
            if (i < words.length-1) sb.append(' ');
            sb.append(words[i]);
        }
        return sb.toString();
    }
    static boolean isPalindrome(String s) {
        int lo=0, hi=s.length()-1;
        while(lo<hi){
            while(lo<hi&&!Character.isLetterOrDigit(s.charAt(lo))) lo++;
            while(lo<hi&&!Character.isLetterOrDigit(s.charAt(hi))) hi--;
            if(Character.toLowerCase(s.charAt(lo))!=Character.toLowerCase(s.charAt(hi))) return false;
            lo++; hi--;
        }
        return true;
    }
    static int[] frequencyMap(String s) {
        int[] freq = new int[26];
        for(char c: s.toLowerCase().toCharArray())
            if(c>='a'&&c<='z') freq[c-'a']++;
        return freq;
    }
    static String compressRunLength(String s) {
        if(s.isEmpty()) return "";
        StringBuilder sb = new StringBuilder();
        int i=0;
        while(i<s.length()){
            char c=s.charAt(i); int cnt=0;
            while(i<s.length()&&s.charAt(i)==c){i++;cnt++;}
            sb.append(c).append(cnt);
        }
        return sb.toString();
    }
    public static void main(String[] args){
        System.out.println("reverseWords('the sky is blue')='" + reverseWords("the sky is blue") + "'");
        System.out.println("isPalindrome('A man a plan a canal Panama')=" + isPalindrome("A man, a plan, a canal: Panama"));
        int[] freq=frequencyMap("hello");
        System.out.println("freq('hello') e=" + freq['e'-'a'] + " l=" + freq['l'-'a']);
        System.out.println("compressRunLength('aaabbc')='" + compressRunLength("aaabbc") + "'");
        boolean allPass = reverseWords("the sky is blue").equals("blue is sky the")
            && isPalindrome("A man, a plan, a canal: Panama")
            && freq['l'-'a']==2
            && compressRunLength("aaabbc").equals("a3b2c1");
        System.out.println("All pass: " + allPass);
    }
}
